    echo "📦 Repository: $repo"
    
    # Get all unique image packages (excluding version/tag)
    local images=$(gcloud artifacts docker images list us-central1-docker.pkg.dev/$PROJECT_ID/$repo --limit=1000 --format="value(package)" 2>&1 | sed 's/@.*$//' | sort -u)
    
    if [ -z "$images" ]; then
        echo "  No images found"
        return
    fi
    
    local image_count=$(echo "$images" | wc -l)
    echo "  Found $image_count unique image(s)"
    
    # Process each unique image
    for image_base in $images; do
        echo ""
        echo "  Image: $image_base"
        
        # Get all versions for this image, sorted by update_time (newest first)
        local all_versions=$(gcloud artifacts docker images list "$image_base" --limit=1000 --sort-by=~update_time --format="value(package)" 2>&1)
        local total=$(echo "$all_versions" | grep -v "^$" | wc -l)
        
        if [ $total -le $KEEP_IMAGES ]; then
            echo "    Total: $total | Keeping all (within limit)"
            continue
        fi
        
        # Get versions to keep (first KEEP_IMAGES)
        local keep=$(echo "$all_versions" | head -n $KEEP_IMAGES)
        # Get versions to delete (rest)
        local to_delete=$(echo "$all_versions" | tail -n +$((KEEP_IMAGES + 1)) | grep -v "^$")
        
        local delete_count=$(echo "$to_delete" | grep -v "^$" | wc -l)
        echo "    Total: $total | Keeping: $KEEP_IMAGES | Deleting: $delete_count"
        
        # Delete old versions
        for version in $to_delete; do
            if [ ! -z "$version" ]; then
                echo "      Deleting: $version"
                gcloud artifacts docker images delete "$version" --quiet --delete-tags 2>&1
                if [ $? -eq 0 ]; then
                    echo "      ✅ Deleted"
                else
                    echo "      ❌ Failed"
                fi
            fi
        done
    done
}

# Main execution
echo "This script will:"
echo "  1. List all Docker images in each repository"
echo "  2. Keep only the latest $KEEP_IMAGES images per service"
echo "  3. Delete older images to reduce storage costs"
echo ""
read -p "Continue? (y/n) " -n 1 -r
echo ""
if [[ ! $REPLY =~ ^[Yy]$ ]]; then
    echo "Cancelled."
    exit 1
fi

# Process each repository
cleanup_repo "cloud-run-source-deploy"
cleanup_repo "gcf-artifacts"
cleanup_repo "jobs"

echo ""
echo "✅ Cleanup complete!"
echo ""
echo "Checking updated storage..."
gcloud artifacts repositories describe gcr.io --project=$PROJECT_ID --location=us --format="get(name,Repository Size)" 2>&1
